import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import BookCard from '../components/BookCard';
import './Home.css';

export default function Home() {
  const [books, setBooks]   = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetch('/api/popular')
      .then(r => r.json())
      .then(data => { setBooks(data); setLoading(false); })
      .catch(() => setLoading(false));
  }, []);

  return (
    <div className="home">

      {/* ── Hero ── */}
      <section className="hero">
        <div className="hero__bg">
          <div className="hero__blob hero__blob--1" />
          <div className="hero__blob hero__blob--2" />
          <div className="hero__grid" />
        </div>
        <div className="container hero__content">
          <div className="hero__text fade-up">
            <span className="hero__eyebrow">AI-Powered Discovery</span>
            <h1 className="hero__headline">
              Find your next<br />
              <em>great read.</em>
            </h1>
            <p className="hero__sub">
              Intelligent recommendations powered by collaborative filtering —
              curated from thousands of reader preferences.
            </p>
            <div className="hero__actions">
              <Link to="/recommend" className="btn-primary">Get Recommendations →</Link>
              <a href="#top50" className="btn-ghost">Browse Top 50</a>
            </div>
          </div>
          <div className="hero__stats fade-up" style={{ animationDelay: '200ms' }}>
            {[['50+', 'Curated Books'], ['1M+', 'Ratings Analysed'], ['98%', 'Satisfaction']].map(([n, l]) => (
              <div key={l} className="hero__stat">
                <strong>{n}</strong>
                <span>{l}</span>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* ── Top 50 Grid ── */}
      <section className="top50" id="top50">
        <div className="container">
          <div className="section-header">
            <h2>Top 50 Books</h2>
            <p>Ranked by reader ratings and popularity</p>
          </div>

          {loading ? (
            <div className="book-grid">
              {Array(12).fill(0).map((_, i) => (
                <div key={i} className="book-card-skeleton">
                  <div className="skeleton" style={{ height: 260, borderRadius: 12 }} />
                  <div className="skeleton" style={{ height: 16, margin: '12px 0 6px', borderRadius: 6 }} />
                  <div className="skeleton" style={{ height: 12, width: '60%', borderRadius: 6 }} />
                </div>
              ))}
            </div>
          ) : (
            <div className="book-grid">
              {books.map((b, i) => (
                <BookCard key={i} {...b} delay={Math.min(i * 40, 600)} />
              ))}
            </div>
          )}
        </div>
      </section>

    </div>
  );
}
